+fn find_last_top_level_optional_chain(s: &str) -> Option<usize> {
+    let bytes = s.as_bytes();
+    let mut depth_paren: i64 = 0;
+    let mut depth_bracket: i64 = 0;
+    let mut depth_brace: i64 = 0;
+    let mut in_quote: Option<u8> = None;
+    let mut escaped = false;
+    let mut last_optional: Option<usize> = None;
+    let mut i = 0usize;
+
+    while i + 1 < bytes.len() {
+        let b = bytes[i];
+        if let Some(q) = in_quote {
+            if escaped {
+                escaped = false;
+                i += 1;
+                continue;
+            }
+            if b == b'\\' {
+                escaped = true;
+                i += 1;
+                continue;
+            }
+            if b == q {
+                in_quote = None;
+            }
+            i += 1;
+            continue;
+        }
+        match b {
+            b'\'' | b'"' | b'`' => {
+                in_quote = Some(b);
+                i += 1;
+                continue;
+            }
+            b'(' => {
+                depth_paren += 1;
+                i += 1;
+                continue;
+            }
+            b')' => {
+                depth_paren -= 1;
+                i += 1;
+                continue;
+            }
+            b'[' => {
+                depth_bracket += 1;
+                i += 1;
+                continue;
+            }
+            b']' => {
+                depth_bracket -= 1;
+                i += 1;
+                continue;
+            }
+            b'{' => {
+                depth_brace += 1;
+                i += 1;
+                continue;
+            }
+            b'}' => {
+                depth_brace -= 1;
+                i += 1;
+                continue;
+            }
+            _ => {}
+        }
+        if depth_paren == 0
+            && depth_bracket == 0
+            && depth_brace == 0
+            && b == b'?'
+            && bytes[i + 1] == b'.'
+        {
+            last_optional = Some(i);
+            i += 2;
+            continue;
+        }
+        i += 1;
+    }
+
+    last_optional
